    [HttpGet("search")]
    public async Task<IActionResult> SearchUsersByEmail([FromQuery] string email)
    {
        if (string.IsNullOrWhiteSpace(email))
        {
            return BadRequest("Email query parameter cannot be empty.");
        }

        var users = new List<User>();

        string sql = "SELECT Id, Name, Email FROM Users WHERE Email LIKE @EmailPattern ORDER BY Email";

        try
        {
            using (var connection = new SqlConnection(_connectionString))
            {
                await connection.OpenAsync();
                using (var command = new SqlCommand(sql, connection))
